class ProductionRecord { public string Date; public int Total; public int Good; public ProductionRecord(string d, int t, int g) { Date=d; Total=t; Good=g; } }

var records = new List<ProductionRecord>();
records.Add(new ProductionRecord("5/1", 1000, 985));
records.Add(new ProductionRecord("5/2", 1200, 1180));
records.Add(new ProductionRecord("5/3", 1100, 1090));

int t = 0, g = 0;
foreach (var r in records) { t += r.Total; g += r.Good; Print($"{r.Date}: 产量{r.Total} 良品{r.Good}"); }
Print($"总产量: {t}, 良品率: {g*100.0/t:F1}%");
